@push('scripts')<script>const checks=[...document.querySelectorAll('.compare-check')],btn=document.getElementById('compare-btn'),count=document.getElementById('selected-count');checks.forEach(c=>c.addEventListener('change',()=>{let active=checks.filter(x=>x.checked);if(active.length>3){c.checked=false;Swal.fire('Maksimal 3 kendaraan','Hapus salah satu pilihan terlebih dahulu.','warning');active=checks.filter(x=>x.checked)}count.textContent=active.length;btn.disabled=active.length<2}));</script>@endpush
